import React, { useEffect, useState } from 'react';
import { Helmet } from 'react-helmet';
import styled, { createGlobalStyle } from 'styled-components';
import '@fontsource/jost/400.css';
import '@fontsource/jost/600.css';
import '@fontsource/jost/700.css';
import stories from '../data/madlibs';

const STORAGE_KEY = 'madlibs-group-game-v1';

const getRandomStory = () => stories[Math.floor(Math.random() * stories.length)];

const renderStory = (template, answers) =>
  template.split(/(\{\{\d+\}\})/).map((part, index) => {
    const placeholder = part.match(/^\{\{(\d+)\}\}$/);

    return placeholder ? (
      <Answer key={index}>{answers[Number(placeholder[1])]}</Answer>
    ) : (
      part
    );
  });

const readSavedGame = () => {
  if (typeof window === 'undefined') {
    return null;
  }

  try {
    const saved = window.localStorage.getItem(STORAGE_KEY);
    const game = saved ? JSON.parse(saved) : null;

    if (
      !game ||
      !Number.isInteger(game.storyIndex) ||
      !stories[game.storyIndex] ||
      !Array.isArray(game.answers)
    ) {
      return null;
    }

    return game;
  } catch (error) {
    return null;
  }
};

const MadlibsPage = () => {
  const [savedGame, setSavedGame] = useState(null);
  const [game, setGame] = useState(null);
  const [screen, setScreen] = useState('welcome');
  const [isReady, setIsReady] = useState(false);

  useEffect(() => {
    setSavedGame(readSavedGame());
    setIsReady(true);
  }, []);

  useEffect(() => {
    if (!isReady || !game || screen === 'welcome') {
      return;
    }

    try {
      window.localStorage.setItem(
        STORAGE_KEY,
        JSON.stringify({
          ...game,
          screen,
          savedAt: new Date().toISOString(),
        })
      );
      setSavedGame({ ...game, screen });
    } catch (error) {
      // The game remains usable if a browser blocks local storage.
    }
  }, [game, isReady, screen]);

  const startGame = () => {
    const story = getRandomStory();
    const storyIndex = stories.indexOf(story);
    setGame({
      storyIndex,
      answers: Array(story.prompts.length).fill(''),
      currentPrompt: 0,
    });
    setScreen('play');
  };

  const resumeGame = () => {
    setGame(savedGame);
    setScreen(savedGame.screen === 'reveal' ? 'reveal' : 'play');
  };

  const resetGame = () => {
    try {
      window.localStorage.removeItem(STORAGE_KEY);
    } catch (error) {
      // The visual state still resets when local storage is unavailable.
    }
    setSavedGame(null);
    setGame(null);
    setScreen('welcome');
  };

  const updateAnswer = (value) => {
    const answers = [...game.answers];
    answers[game.currentPrompt] = value;
    setGame({ ...game, answers });
  };

  const nextPrompt = (event) => {
    event.preventDefault();
    if (!game.answers[game.currentPrompt].trim()) {
      return;
    }

    if (game.currentPrompt === stories[game.storyIndex].prompts.length - 1) {
      setScreen('reveal');
      return;
    }

    setGame({ ...game, currentPrompt: game.currentPrompt + 1 });
  };

  const previousPrompt = () => {
    if (game.currentPrompt > 0) {
      setGame({ ...game, currentPrompt: game.currentPrompt - 1 });
    }
  };

  const story = game ? stories[game.storyIndex] : null;
  const promptNumber = game ? game.currentPrompt + 1 : 0;
  const progress = game
    ? (promptNumber / stories[game.storyIndex].prompts.length) * 100
    : 0;

  return (
    <>
      <PageStyle />
      <Helmet>
        <html lang="en" />
        <title>Table Tales | Group Madlibs</title>
        <meta
          name="description"
          content="A conversation-first Madlib game for groups."
        />
        <meta name="theme-color" content="#f7b267" />
        <meta name="viewport" content="width=device-width, initial-scale=1" />
      </Helmet>
      <App>
        <Main>
          <Brand aria-label="Table Tales">
            <Mark aria-hidden="true">✦</Mark>
            <span>Table Tales</span>
          </Brand>

          {screen === 'welcome' && (
            <WelcomeCard>
              <Eyebrow>Group Madlibs</Eyebrow>
              <Title>Turn conversation into a story.</Title>
              <Lead>
                Gather 4–5 people, choose one person to type, and build a
                wonderfully strange tale together.
              </Lead>
              <RuleList>
                <li>Discuss each prompt before writing one shared answer.</li>
                <li>Five prompts. About five minutes. Zero pressure.</li>
                <li>Your game stays on this phone, even after a refresh.</li>
              </RuleList>
              <PrimaryButton type="button" onClick={startGame}>
                Start a new tale <span aria-hidden="true">→</span>
              </PrimaryButton>
              {isReady && savedGame && (
                <ResumeBox>
                  <div>
                    <strong>Welcome back</strong>
                    <span>
                      {stories[savedGame.storyIndex].title} is waiting for
                      your group.
                    </span>
                  </div>
                  <SecondaryButton type="button" onClick={resumeGame}>
                    Resume
                  </SecondaryButton>
                </ResumeBox>
              )}
            </WelcomeCard>
          )}

          {screen === 'play' && game && (
            <GameCard>
              <GameHeader>
                <div>
                  <Eyebrow>{story.title}</Eyebrow>
                  <GameIntro>{story.intro}</GameIntro>
                </div>
                <Counter>
                  {promptNumber} <span>/ {story.prompts.length}</span>
                </Counter>
              </GameHeader>
              <Progress aria-label={`Prompt ${promptNumber} of ${story.prompts.length}`}>
                <ProgressFill style={{ width: `${progress}%` }} />
              </Progress>
              <PromptForm onSubmit={nextPrompt}>
                <PromptLabel htmlFor="madlib-answer">
                  Talk it out, then choose:
                </PromptLabel>
                <Prompt>{story.prompts[game.currentPrompt]}</Prompt>
                <TextInput
                  id="madlib-answer"
                  value={game.answers[game.currentPrompt]}
                  onChange={(event) => updateAnswer(event.target.value)}
                  placeholder="Your group’s answer"
                  autoComplete="off"
                  autoFocus
                />
                <ActionRow>
                  <BackButton
                    type="button"
                    onClick={previousPrompt}
                    disabled={game.currentPrompt === 0}
                  >
                    Back
                  </BackButton>
                  <PrimaryButton type="submit">
                    {game.currentPrompt === story.prompts.length - 1
                      ? 'Reveal our tale'
                      : 'Next prompt'}{' '}
                    <span aria-hidden="true">→</span>
                  </PrimaryButton>
                </ActionRow>
              </PromptForm>
              <PersistenceNote>
                Saved automatically on this device.
              </PersistenceNote>
            </GameCard>
          )}

          {screen === 'reveal' && game && (
            <RevealCard>
              <Eyebrow>Your completed tale</Eyebrow>
              <Title>{story.title}</Title>
              <StoryText>{renderStory(story.template, game.answers)}</StoryText>
              <Celebration>Made by your table. Nicely done.</Celebration>
              <ActionRow>
                <PrimaryButton type="button" onClick={startGame}>
                  Play another <span aria-hidden="true">→</span>
                </PrimaryButton>
              </ActionRow>
            </RevealCard>
          )}
        </Main>
        {screen !== 'welcome' && (
          <Footer>
            <button type="button" onClick={resetGame}>
              Start over
            </button>
          </Footer>
        )}
      </App>
    </>
  );
};

export default MadlibsPage;

const PageStyle = createGlobalStyle`
  html, body, #___gatsby, #gatsby-focus-wrapper {
    min-height: 100%;
  }

  body {
    margin: 0;
  }

  * {
    box-sizing: border-box;
  }
`;

const App = styled.div`
  min-height: 100vh;
  color: #21314d;
  background:
    radial-gradient(circle at 10% 10%, rgba(255, 237, 184, 0.9), transparent 32rem),
    radial-gradient(circle at 90% 85%, rgba(193, 223, 238, 0.8), transparent 28rem),
    #f8f5ee;
  font-family: 'Jost', system-ui, sans-serif;
`;

const Main = styled.main`
  width: min(100%, 42rem);
  margin: 0 auto;
  padding: clamp(2rem, 8vw, 5rem) 1.25rem 2rem;
`;

const Brand = styled.div`
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  margin-bottom: clamp(2.5rem, 10vw, 5rem);
  color: #375a7f;
  font-size: 1.1rem;
  font-weight: 700;
  letter-spacing: 0.03em;
`;

const Mark = styled.span`
  display: grid;
  width: 1.9rem;
  height: 1.9rem;
  place-items: center;
  border-radius: 50%;
  background: #f7b267;
  color: #21314d;
`;

const Card = styled.section`
  border: 1px solid rgba(33, 49, 77, 0.08);
  border-radius: 1.5rem;
  background: rgba(255, 255, 255, 0.86);
  box-shadow: 0 1.25rem 3.5rem rgba(33, 49, 77, 0.1);
`;

const WelcomeCard = styled(Card)`
  padding: clamp(1.75rem, 7vw, 3.5rem);
`;

const GameCard = styled(Card)`
  overflow: hidden;
`;

const RevealCard = styled(Card)`
  padding: clamp(1.75rem, 7vw, 3.5rem);
`;

const Eyebrow = styled.p`
  margin: 0 0 0.75rem;
  color: #b45e43;
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.14em;
  text-transform: uppercase;
`;

const Title = styled.h1`
  margin: 0;
  color: #21314d;
  font-size: clamp(2.4rem, 10vw, 4.35rem);
  line-height: 0.98;
  letter-spacing: -0.055em;
`;

const Lead = styled.p`
  max-width: 31rem;
  margin: 1.5rem 0;
  color: #52647f;
  font-size: clamp(1.05rem, 3.5vw, 1.22rem);
  line-height: 1.55;
`;

const RuleList = styled.ul`
  display: grid;
  gap: 0.65rem;
  margin: 2rem 0;
  padding: 0;
  color: #3e526f;
  line-height: 1.45;
  list-style: none;

  li {
    display: flex;
    gap: 0.75rem;
  }

  li::before {
    content: '✦';
    color: #df7d54;
  }
`;

const Button = styled.button`
  min-height: 3.25rem;
  padding: 0.75rem 1.1rem;
  border: 0;
  border-radius: 0.75rem;
  font: inherit;
  font-weight: 700;
  cursor: pointer;
  transition: transform 150ms ease, box-shadow 150ms ease;

  &:focus-visible {
    outline: 3px solid #375a7f;
    outline-offset: 3px;
  }

  &:not(:disabled):hover {
    transform: translateY(-2px);
  }

  &:disabled {
    cursor: not-allowed;
    opacity: 0.35;
  }
`;

const PrimaryButton = styled(Button)`
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.7rem;
  width: 100%;
  background: #21314d;
  box-shadow: 0 0.4rem 0 #152239;
  color: #fff;

  span {
    font-size: 1.25rem;
    line-height: 1;
  }
`;

const SecondaryButton = styled(Button)`
  background: #eaf0f3;
  color: #21314d;
`;

const ResumeBox = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  margin-top: 1.75rem;
  padding: 1rem;
  border-radius: 0.9rem;
  background: #fff5dd;

  div {
    display: grid;
    gap: 0.15rem;
  }

  strong {
    color: #21314d;
  }

  span {
    color: #62664f;
    font-size: 0.9rem;
    line-height: 1.3;
  }

  button {
    flex: 0 0 auto;
  }
`;

const GameHeader = styled.div`
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  padding: clamp(1.5rem, 6vw, 2.5rem) clamp(1.5rem, 6vw, 3rem) 1.25rem;
`;

const GameIntro = styled.p`
  max-width: 27rem;
  margin: 0;
  color: #52647f;
  line-height: 1.45;
`;

const Counter = styled.div`
  flex: 0 0 auto;
  color: #21314d;
  font-size: 1.5rem;
  font-weight: 700;

  span {
    color: #8591a4;
    font-size: 1rem;
  }
`;

const Progress = styled.div`
  height: 0.45rem;
  margin: 0 clamp(1.5rem, 6vw, 3rem);
  overflow: hidden;
  border-radius: 1rem;
  background: #eaf0f3;
`;

const ProgressFill = styled.div`
  height: 100%;
  border-radius: inherit;
  background: #f29e4c;
  transition: width 220ms ease;
`;

const PromptForm = styled.form`
  padding: clamp(2rem, 8vw, 3.5rem) clamp(1.5rem, 6vw, 3rem) 1.5rem;
`;

const PromptLabel = styled.label`
  display: block;
  margin-bottom: 0.5rem;
  color: #b45e43;
  font-size: 0.8rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
`;

const Prompt = styled.p`
  margin: 0 0 1.75rem;
  color: #21314d;
  font-size: clamp(1.55rem, 6vw, 2.35rem);
  font-weight: 700;
  letter-spacing: -0.035em;
  line-height: 1.12;
`;

const TextInput = styled.input`
  width: 100%;
  min-height: 3.75rem;
  margin-bottom: 1.25rem;
  padding: 0.75rem 1rem;
  border: 2px solid #cfdae1;
  border-radius: 0.75rem;
  background: #fff;
  color: #21314d;
  font: inherit;
  font-size: 1.1rem;

  &:focus {
    border-color: #375a7f;
    outline: 0;
    box-shadow: 0 0 0 3px rgba(55, 90, 127, 0.15);
  }
`;

const ActionRow = styled.div`
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 0.8rem;

  ${PrimaryButton} {
    width: auto;
  }

  @media (max-width: 26rem) {
    align-items: stretch;
    flex-direction: column-reverse;

    ${PrimaryButton} {
      width: 100%;
    }
  }
`;

const BackButton = styled.button`
  padding: 0.75rem;
  border: 0;
  background: transparent;
  color: #52647f;
  font: inherit;
  font-weight: 700;
  cursor: pointer;

  &:focus-visible {
    outline: 3px solid #375a7f;
    outline-offset: 3px;
  }
`;

const PersistenceNote = styled.p`
  margin: 0;
  padding: 0 1.5rem 1.5rem;
  color: #79879b;
  font-size: 0.82rem;
  text-align: center;
`;

const StoryText = styled.p`
  margin: 1.75rem 0;
  color: #364963;
  font-size: clamp(1.2rem, 4.5vw, 1.6rem);
  line-height: 1.7;
`;

const Answer = styled.strong`
  color: #b45e43;
  font-weight: 700;
`;

const Celebration = styled.p`
  margin: 0 0 1.75rem;
  color: #758093;
  font-size: 0.95rem;
  font-style: italic;
`;

const Footer = styled.footer`
  width: min(100%, 42rem);
  margin: 0 auto;
  padding: 0 1.25rem 2rem;
  text-align: center;

  button {
    border: 0;
    background: transparent;
    color: #52647f;
    font: inherit;
    font-size: 0.85rem;
    text-decoration: underline;
    cursor: pointer;
  }
`;
